options:
  env:
    - 'RAILS_ENV=${_RAILS_ENV}'
  dynamic_substitutions: true
steps:
  # Create rails app image for appengine:exec and rails task
  - name: 'gcr.io/kaniko-project/executor'
    id: 'build-image'
    args:
      - --dockerfile=build/app/builder.dockerfile
      - --destination=${_HPC_RAILS_APP}
      - --cache=true

  # Get credentials from secret manager
  - name: ${_HPC_RAILS_APP}
    id: 'get-secret-key'
    entrypoint: ash
    args:
      - -c
      - |
        gcloud secrets versions access --secret=rails_master_key latest > config/credentials/$$RAILS_ENV.key

  # Generate GAE settings designated RAILS_ENV
  - name: ${_HPC_RAILS_APP}
    id: 'create-app-yml'
    entrypoint: './bin/rails'
    args:
      - 'gae:create_app_yml:run[true]'

  # assets precompile
  - name: ${_HPC_RAILS_APP}
    id: 'create-assets'
    entrypoint: './bin/rails'
    args:
      - 'assets:precompile'

  # Create a deploy tag
  - name: ${_HPC_RAILS_APP}
    id: 'create-tag'
    entrypoint: ash
    args:
      - -c
      - |
        if [ -z $SHORT_SHA ]; then
          date +%Y%m%d-%H%M > _TAG
        else
          date +%Y%m%d-%H%M-$SHORT_SHA > _TAG
        fi

  # Deploy but not to switch yet
  - name: ${_HPC_RAILS_APP}
    id: 'deploy-app-no-promoto'
    entrypoint: ash
    args:
      - -c
      - |
        gcloud app deploy -v $(cat _TAG) --no-promote --quiet

  # Rails db migrate
  - name: ${_HPC_RAILS_APP}
    id: 'db-migrate'
    env:
      - 'SETTINGS_DATABASE_HOST=localhost'
    entrypoint: ash
    args:
      - '-c'
      - |
        cloud-sql-proxy ${_INSTANCE_CONNECTION_NAME} -p 5432 & sleep 2;
        ./bin/rails db:migrate
  # Switch to new app
  - name: ${_HPC_RAILS_APP}
    id: 'set-traffic-to-new-app'
    entrypoint: ash
    args:
      - -c
      - |
        gcloud app services set-traffic default --splits $(cat _TAG)=1 --quiet
timeout: 1800s
