provider "google" {
  project = var.project_id
  region  = var.region
}

resource "google_secret_manager_secret" "rails_master_key" {
  secret_id = "rails-master-key"

  replication {
    auto {}
  }

  depends_on = [google_project_service.required]
}

resource "google_secret_manager_secret" "database_password" {
  secret_id = "database-password"

  replication {
    auto {}
  }

  depends_on = [google_project_service.required]
}

output "app_engine_url" {
  value = "https://${var.project_id}.${var.app_engine_location}.r.appspot.com"
}

output "cloud_sql_connection_name" {
  value = google_sql_database_instance.primary.connection_name
}

output "cloudbuild_service_account" {
  value = google_service_account.cloudbuild_deployer.email
}

resource "google_sql_database_instance" "primary" {
  name                = "rails8-todo-postgres"
  database_version    = "POSTGRES_16"
  region              = var.region
  deletion_protection = true

  settings {
    tier              = var.cloud_sql_tier
    availability_type = "ZONAL"
    disk_type         = "PD_SSD"
    disk_size         = 10
    disk_autoresize   = true

    backup_configuration {
      enabled = true
    }

    database_flags {
      name  = "timezone"
      value = "Asia/Tokyo"
    }
  }

  depends_on = [google_project_service.required]
}

resource "google_sql_database" "application" {
  name     = var.database_name
  instance = google_sql_database_instance.primary.name
}

resource "google_sql_user" "application" {
  name     = var.database_user
  instance = google_sql_database_instance.primary.name
  password = var.database_password
}

terraform {
  required_version = ">= 1.6.0"

  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 7.0"
    }
  }
}

resource "google_service_account" "app_engine" {
  account_id   = "app-engine-runtime"
  display_name = "App Engine runtime"
}

resource "google_service_account" "cloudbuild_deployer" {
  account_id   = "cloudbuild-deployer"
  display_name = "Cloud Build App Engine deployer"
}

resource "google_project_iam_member" "app_engine_cloud_sql" {
  project = var.project_id
  role    = "roles/cloudsql.client"
