steps:
  - id: build-image
    name: gcr.io/cloud-builders/docker
    args:
      - build
      - --file=docker/app/Dockerfile
      - --tag=${_IMAGE_URL}:$SHORT_SHA
      - .

  - id: push-image
    name: gcr.io/cloud-builders/docker
    args:
      - push
      - ${_IMAGE_URL}:$SHORT_SHA

  # Terraform owns the Job configuration. Cloud Build only replaces its image,
  # executes it, and waits for the migration to complete.
  - id: run-migration-job
    name: gcr.io/google.com/cloudsdktool/cloud-sdk:slim
    entrypoint: bash
    args:
      - -ceu
      - |
        gcloud run jobs update "${_CLOUD_RUN_SERVICE}-migrate" \
          --image="${_IMAGE_URL}:$SHORT_SHA" \
          --region="${_CLOUD_RUN_REGION}" \
          --wait \
          --quiet

  - id: deploy-cloud-run
    name: gcr.io/google.com/cloudsdktool/cloud-sdk:slim
    entrypoint: bash
    args:
      - -ceu
      - |
        gcloud run deploy "${_CLOUD_RUN_SERVICE}" \
          --image="${_IMAGE_URL}:$SHORT_SHA" \
          --region="${_CLOUD_RUN_REGION}" \
          --allow-unauthenticated \
          --quiet

