name: Deploy

on:
  workflow_run:
    workflows: [CI]
    types: [completed]
    branches: [main]

permissions:
  contents: read
  id-token: write

concurrency:
  group: production-deploy
  cancel-in-progress: false

jobs:
  deploy:
    if: >-
      github.event.workflow_run.conclusion == 'success' &&
      github.event.workflow_run.event == 'push' &&
      github.event.workflow_run.head_branch == 'main'
    runs-on: ubuntu-latest
    environment: production
    env:
      CLOUD_RUN_REGION: asia-northeast1
      CLOUD_RUN_SERVICE: rails8-todo
      GCP_PROJECT_ID: ${{ vars.GCP_PROJECT_ID }}
      IMAGE_URL: asia-northeast1-docker.pkg.dev/${{ vars.GCP_PROJECT_ID }}/rails8-todo/app
      IMAGE_TAG: ${{ github.event.workflow_run.head_sha }}

    steps:
      - name: Checkout code
        uses: actions/checkout@v6
        with:
          ref: ${{ github.event.workflow_run.head_sha }}

      - name: Authenticate to Google Cloud
        id: auth
        uses: google-github-actions/auth@v2
        with:
          workload_identity_provider: ${{ vars.GCP_WORKLOAD_IDENTITY_PROVIDER }}
          service_account: ${{ vars.GCP_DEPLOY_SERVICE_ACCOUNT }}

      - name: Set up Google Cloud CLI
        uses: google-github-actions/setup-gcloud@v2

      - name: Configure Docker for Artifact Registry
        run: gcloud auth configure-docker "$CLOUD_RUN_REGION-docker.pkg.dev" --quiet

      - name: Build and push image
        run: |
          docker build --file=docker/app/Dockerfile --tag="$IMAGE_URL:$IMAGE_TAG" .
          docker push "$IMAGE_URL:$IMAGE_TAG"

      - name: Run database migrations
        run: |
          gcloud run jobs update "$CLOUD_RUN_SERVICE-migrate" \
            --image="$IMAGE_URL:$IMAGE_TAG" \
            --project="$GCP_PROJECT_ID" \
            --region="$CLOUD_RUN_REGION" \
            --wait \
            --quiet

      - name: Deploy Cloud Run service
        run: |
          gcloud run deploy "$CLOUD_RUN_SERVICE" \
            --image="$IMAGE_URL:$IMAGE_TAG" \
            --project="$GCP_PROJECT_ID" \
            --region="$CLOUD_RUN_REGION" \
            --allow-unauthenticated \
            --quiet

